+// ===============================================
+// Theme switching (Light / Dark / System)
+// ===============================================
+(function initTheme() {
+  const stored = localStorage.getItem('pr-pack-theme') || 'system';
+  applyTheme(stored);
+  updateThemeButtons(stored);
+})();
+
+function setTheme(theme) {
+  localStorage.setItem('pr-pack-theme', theme);
+  applyTheme(theme);
+  updateThemeButtons(theme);
+}
+
+function applyTheme(theme) {
+  if (theme === 'system') {
+    const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
+    document.documentElement.setAttribute('data-theme', prefersDark ? 'dark' : 'light');
+  } else {
+    document.documentElement.setAttribute('data-theme', theme);
+  }
+}
+
+function updateThemeButtons(theme) {
+  document.querySelectorAll('.theme-toggle button').forEach(btn => {
+    btn.classList.toggle('active', btn.getAttribute('data-theme-btn') === theme);
+  });
+}
+
+window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', () => {
+  const stored = localStorage.getItem('pr-pack-theme') || 'system';
+  if (stored === 'system') applyTheme('system');
+});
+
+// ===============================================
+// CI job detail toggle
+// ===============================================
+function toggleCIDetail(row) {
+  const detail = row.nextElementSibling;
+  if (detail && detail.classList.contains('detail-row')) {
+    detail.classList.toggle('open');
+    row.classList.toggle('ci-open');
+  }
+}
+
+// ===============================================
+// Decision card toggle + zone highlighting
+// ===============================================
+function toggleDecision(card) {
+  const wasOpen = card.classList.contains('open');
+  document.querySelectorAll('.decision-card').forEach(c => c.classList.remove('open'));
+  const savedY = window.scrollY;
+  if (!wasOpen) {
+    card.classList.add('open');
+    const zones = card.dataset.zones.split(' ');
+    highlightZones(zones);
+  } else {
+    resetZones();
+  }
+  // Restore scroll position — zone filtering hides/shows cards causing layout shift
+  window.scrollTo(0, savedY);
+}
+
+// ===============================================
+// Adversarial review row toggle (legacy, kept for backward compat)
+// ===============================================
+function toggleAdvDetail(row) {
+  const detail = row.nextElementSibling;
+  if (detail && detail.classList.contains('adv-detail-row')) {
+    detail.classList.toggle('open');
+  }
+}
+
+// ===============================================
+// Code Review table row toggle (per-agent detail expansion)
+// ===============================================
+function toggleCRDetail(row) {
+  const detail = row.nextElementSibling;
+  if (detail && detail.classList.contains('cr-detail-row')) {
+    detail.classList.toggle('open');
+    // Handle zone filtering visibility
+    if (detail.classList.contains('open') && detail.style.display === 'none') {
+      detail.style.display = '';
+    }
+  }
+}
+
+// Legacy code review file toggle (kept for backward compat)
+function toggleCodeReviewFile(item, filePath) {
+  const wasOpen = item.classList.contains('open');
+  document.querySelectorAll('#cr-file-list .cd-file-item').forEach(i => i.classList.remove('open'));
+  if (!wasOpen) {
+    item.classList.add('open');
+    const body = item.querySelector('.cd-file-body');
+    if (body && !body.dataset.loaded) {
+      body.dataset.loaded = 'true';
+      const diffContent = body.querySelector('.cd-file-diff-content');
+      if (diffContent) {
+        loadDiffData((data, err) => {
+          if (err || !data) { diffContent.innerHTML = '<div class="diff-error">Failed to load.</div>'; return; }
+          const fileData = data.files[filePath];
+          if (!fileData) { diffContent.innerHTML = '<div class="diff-error">File not in diff data.</div>'; return; }
+          renderInlineDiff(item, fileData, 'side-by-side');
+        });
+      }
+    }
+  }
+}
+
+// ===============================================
+// Architecture zone highlighting (cross-section filtering)
+// ===============================================
+let currentActiveZones = null;
+
+function highlightZones(activeZones) {
+  currentActiveZones = activeZones;
+
+  // 1. Highlight zones in main diagram
+  document.querySelectorAll('#arch-diagram .zone-box').forEach(box => {
+    const zone = box.dataset.zone;
+    if (activeZones.includes(zone)) {
+      box.classList.remove('dimmed');
+      box.classList.add('highlighted');
+    } else {
+      box.classList.add('dimmed');
+      box.classList.remove('highlighted');
+    }
+  });
+
+  const info = document.getElementById('zone-filter-info');
+  info.textContent = 'Showing zones: ' + activeZones.join(', ');
+  info.style.display = 'block';
+
+  // 2. Filter code review file list (supports both table rows and list items)
+  let anyMatch = false;
+  document.querySelectorAll('#cr-file-list .cr-file-row, #cr-file-list .cd-file-item').forEach(item => {
+    const itemZones = (item.dataset.zones || '').split(' ');
+    const match = itemZones.some(z => activeZones.includes(z));
+    item.style.display = match ? '' : 'none';
+    // Also hide corresponding detail row if table
+    if (item.classList.contains('cr-file-row')) {
+      const detail = item.nextElementSibling;
+      if (detail && detail.classList.contains('cr-detail-row')) {
+        detail.style.display = match && detail.classList.contains('open') ? '' : 'none';
+      }
+    }
+    if (match) anyMatch = true;
+  });
+  const noMatch = document.getElementById('cr-no-match');
+  if (noMatch) noMatch.classList.toggle('visible', !anyMatch);
+
+  // 3. Filter scenario cards
+  document.querySelectorAll('.scenario-card[data-zone]').forEach(card => {
+    const cardZones = card.dataset.zone.split(' ');
+    const match = cardZones.some(z => activeZones.includes(z));
+    card.classList.toggle('zone-dimmed', !match);
+    card.classList.toggle('zone-glow', match);
+  });
+
+  // 4. Filter What Changed section
+  const wcDefault = document.getElementById('wc-default');
+  if (wcDefault) wcDefault.style.display = 'none';
+  document.querySelectorAll('.wc-zone-detail').forEach(d => {
+    d.classList.toggle('active', activeZones.includes(d.dataset.zone));
+  });
+  if (!document.querySelector('.wc-zone-detail.active') && wcDefault) {
+    wcDefault.style.display = '';
+  }
+
+  // 5. Sync sidebar zone mini-map
+  document.querySelectorAll('.sb-zone-item').forEach(item => {
+    item.classList.toggle('active', activeZones.includes(item.dataset.zone));
+  });
+  const activeLabel = document.getElementById('sb-zone-active');
+  if (activeLabel) activeLabel.textContent = 'Active: ' + activeZones.join(', ');
+  document.querySelectorAll('.sb-clear-filter').forEach(function(btn) { btn.classList.add('visible'); });
+
+  // 6. Filter decisions
+  document.querySelectorAll('.decision-card').forEach(card => {
+    const cardZones = (card.dataset.zones || '').split(' ');
+    const match = cardZones.some(z => activeZones.includes(z));
+    card.style.display = match ? '' : 'none';
+  });
+
+  // 7. Sync mini architecture diagram
+  syncMiniDiagram();
+}
+
+function resetZones() {
+  currentActiveZones = null;
+  document.querySelectorAll('.zone-box').forEach(box => box.classList.remove('dimmed', 'highlighted'));
+  document.getElementById('zone-filter-info').style.display = 'none';
+  // Reset code review file list (supports both table rows and list items)
+  document.querySelectorAll('#cr-file-list .cr-file-row, #cr-file-list .cd-file-item').forEach(item => item.style.display = '');
+  document.querySelectorAll('#cr-file-list .cr-detail-row').forEach(item => {
+    item.style.display = item.classList.contains('open') ? '' : 'none';
+  });
+  const noMatch = document.getElementById('cr-no-match');
+  if (noMatch) noMatch.classList.remove('visible');
+  document.querySelectorAll('.scenario-card[data-zone]').forEach(card => card.classList.remove('zone-dimmed', 'zone-glow'));
+  const wcDefault = document.getElementById('wc-default');
+  if (wcDefault) wcDefault.style.display = '';
+  document.querySelectorAll('.wc-zone-detail').forEach(d => d.classList.remove('active'));
+
+  // Reset sidebar zone mini-map
+  document.querySelectorAll('.sb-zone-item').forEach(item => item.classList.remove('active'));
+  const activeLabel = document.getElementById('sb-zone-active');
+  if (activeLabel) activeLabel.textContent = '';
+  document.querySelectorAll('.sb-clear-filter').forEach(function(btn) { btn.classList.remove('visible'); });
+  // Reset decision cards
+  document.querySelectorAll('.decision-card').forEach(card => card.style.display = '');
+  // Sync mini diagram
+  syncMiniDiagram();
+}
