+function scrollToSection(id) {
+  const el = document.getElementById(id);
+  if (!el) return;
+  // Auto-expand any collapsed tier that contains this section
+  const tierContent = el.closest('.tier-content');
+  if (tierContent && tierContent.classList.contains('collapsed')) {
+    tierContent.classList.remove('collapsed');
+    const divider = tierContent.previousElementSibling;
+    if (divider) divider.classList.remove('collapsed');
+  }
+  // Also expand the section itself if collapsed
+  if (el.classList.contains('collapsed')) {
+    el.classList.remove('collapsed');
+  }
+  el.scrollIntoView({ behavior: 'smooth', block: 'start' });
+}
