+}
+
+function renderInlineDiff(item, fileData, view) {
+  const container = item.querySelector('.cd-file-diff-content');
+  // Reuse the same rendering logic as the modal
+  const savedFileData = currentFileData;
+  const savedFilePath = currentFilePath;
+  currentFileData = fileData;
+  currentFilePath = item.dataset.path;
+  if (view === 'raw') renderRawView(container);
+  else if (view === 'integrated') renderUnifiedView(container);
+  else renderSplitView(container);
+  currentFileData = savedFileData;
+  currentFilePath = savedFilePath;
+}
+
+// ===============================================
+// Hamburger menu
+// ===============================================
+function toggleHamburger() {
+  const overlay = document.getElementById('mc-hamburger-overlay');
+  overlay.classList.toggle('visible');
+  document.body.style.overflow = overlay.classList.contains('visible') ? 'hidden' : '';
+}
+
+// ===============================================
+// v2 initialization
+// ===============================================
+function initSidebarMiniDiagram() {
+  renderMiniArchGrid(); // Default: show all zones as chips
+}
+
+function renderMiniArchGrid() {
+  const container = document.getElementById('sb-arch-mini');
+  if (!container || !DATA || !DATA.architecture || !DATA.architecture.zones) return;
+
+  let html = '<div class="sb-arch-grid">';
+  DATA.architecture.zones.forEach(function(zone) {
+    const catClass = zone.category || 'product';
+    const modClass = zone.isModified ? 'modified' : '';
+    const fc = zone.fileCount || 0;
+    html += '<div class="sb-arch-chip ' + catClass + ' ' + modClass + '" ' +
+            'data-zone="' + zone.id + '" ' +
+            'onclick="sidebarZoneClick(\'' + zone.id + '\')" ' +
+            'ondblclick="event.stopPropagation();resetZones()" ' +
+            'title="' + (zone.sublabel || zone.label) + ' (double-click to clear filter)">' +
+            '<span class="sb-arch-chip-label">' + zone.label + '</span>' +
+            (fc > 0 ? '<span class="sb-arch-chip-count">' + fc + '</span>' : '') +
+            '</div>';
+  });
+  // Add unzoned chip if there are unzoned files
+  var assessment = DATA.architectureAssessment;
+  var unzonedFiles = assessment && assessment.unzonedFiles ? assessment.unzonedFiles : [];
+  if (unzonedFiles.length > 0) {
+    html += '<div class="sb-arch-chip unzoned" ' +
+            'onclick="scrollToSection(\'section-arch-assessment\')" ' +
+            'title="' + unzonedFiles.length + ' file(s) not in any zone">' +
+            '<span class="sb-arch-chip-label">&#x26A0; Unzoned</span>' +
+            '<span class="sb-arch-chip-count">' + unzonedFiles.length + '</span>' +
+            '</div>';
+  }
+  html += '</div>';
+  container.innerHTML = html;
+}
+
+function renderMiniArchZoom(zoneId) {
+  const container = document.getElementById('sb-arch-mini');
+  if (!container || !DATA || !DATA.architecture || !DATA.architecture.zones) return;
+
+  const zone = DATA.architecture.zones.find(function(z) { return z.id === zoneId; });
+  if (!zone) return;
+
+  const catClass = zone.category || 'product';
+  const fc = zone.fileCount || 0;
+
+  // Find findings for this zone
+  const findings = (DATA.agenticReview && DATA.agenticReview.findings || []).filter(function(f) {
+    const fZones = (f.zones || '').split(' ');
+    return fZones.includes(zoneId);
+  });
+  const gs = {'F':0,'C':1,'B':2,'B+':3,'A':4,'N/A':5};
+  const worstGrade = findings.reduce(function(worst, f) {
+    return (gs[f.grade] || 5) < (gs[worst] || 5) ? f.grade : worst;
+  }, 'A');
+  const gradeClassMap = {'A':'a','B+':'b','B':'b','C':'c','F':'f','N/A':'na'};
+  const gradeClass = gradeClassMap[worstGrade] || 'na';
+
+  container.innerHTML =
+    '<div class="sb-arch-zoom ' + catClass + '">' +
+    '  <div class="sb-arch-zoom-header">' +
+    '    <span class="sb-arch-zoom-name">' + zone.label + '</span>' +
+    '    <span class="grade ' + gradeClass + '" style="width:24px;height:24px;line-height:24px;font-size:11px">' + worstGrade + '</span>' +
+    '  </div>' +
+    '  <div class="sb-arch-zoom-sub">' + (zone.sublabel || '') + '</div>' +
+    '  <div class="sb-arch-zoom-stats">' +
+    '    <span>' + fc + ' file' + (fc !== 1 ? 's' : '') + ' changed</span>' +
+    '    <span>' + findings.length + ' finding' + (findings.length !== 1 ? 's' : '') + '</span>' +
+    '  </div>' +
+    '</div>';
+}
+
+function syncMiniDiagram() {
+  // Always stay in grid mode so chips remain clickable/double-clickable
+  renderMiniArchGrid();
+  if (currentActiveZones) {
+    document.querySelectorAll('.sb-arch-chip').forEach(function(chip) {
+      if (currentActiveZones.includes(chip.dataset.zone)) {
+        chip.classList.add('highlighted');
+      } else {
+        chip.classList.add('dimmed');
+      }
+    });
+  }
+}
+
+document.addEventListener('DOMContentLoaded', () => {
+  initSectionNav();
+  initSidebarMiniDiagram();
+});
+</script>
+</body>
+</html>

