+  type: "new_zone_recommended" | "zone_split" | "zone_merge" | "zone_renamed" | "zone_removed";
+  zone: string;
+  reason: string;
+  suggestedPaths?: string[];
+}
+
+interface RegistryWarning {
+  zone: string;
+  warning: string;
+  severity: "CRITICAL" | "WARNING" | "NIT";
+}
+
+interface CouplingWarning {
+  fromZone: string;
+  toZone: string;
+  files: string[];
+  evidence: string;
+}
+
