                {"file": "src/a.py", "agent": "adversarial", "grade": "C"},
                {"file": "src/b.py", "agent": "code-health", "grade": "A"},
            ]},
        )
        assert result["value"] == "needs-review"
        assert "1 file(s)" in result["reasons"][0]

    def test_needs_review_commit_gap(self):
