            commit_gap=2,
        )
        assert result["value"] == "needs-review"
        assert len(result["reasons"]) == 2

    def test_blocked_overrides_needs_review(self):
        """F grade produces blocked even with commit gap."""
        result = compute_status(
            self._passing_convergence(),
